#include <iostream>
#include <string>
#include <vector>

struct Patient {
    std::string name;
};

class Doctor {
    Patient* current{nullptr};
public:
    void assign(Patient* p) {
        current = p;
    }
    void report() const {
        if (current)
            std::cout << "Treating: " << current->name << "\n";
        else
            std::cout << "No patient\n";
    }
};

int main() {
    int n{};
    std::cin >> n;
    std::vector<Patient> patients(static_cast<std::size_t>(n));
    for (int i = 0; i < n; ++i)
        std::cin >> patients[static_cast<std::size_t>(i)].name;
    int m{}, k{};
    std::cin >> m >> k;
    Doctor doc;
    doc.assign(&patients[static_cast<std::size_t>(m)]);
    doc.report();
    doc.assign(&patients[static_cast<std::size_t>(k)]);
    doc.report();
    return 0;
}

