#include <iostream>
#include <string>

struct Course;  // forward declaration

struct Instructor {
    std::string name;
    Course* teaching{nullptr};
};

struct Course {
    std::string title;
    Instructor* instructor{nullptr};
};

void assign(Course& c, Instructor& instr) {
    c.instructor = &instr;
    instr.teaching = &c;
}

void printCourse(const Course& c) {
    std::cout << "Course: " << c.title
              << " taught by " << (c.instructor ? c.instructor->name : "nobody")
              << "\n";
}

void printInstructor(const Instructor& instr) {
    std::cout << "Instructor: " << instr.name
              << " teaching " << (instr.teaching ? instr.teaching->title : "nothing")
              << "\n";
}

int main() {
    Course c;
    Instructor i;
    std::cin >> c.title >> i.name;
    assign(c, i);
    printCourse(c);
    printInstructor(i);
    return 0;
}
